Here's a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:
```c++
#include <fstream>
#include <string>
#include <vector>

int main() {
    // Open the file
    std::ifstream file("text_file.txt");
    if (file.fail()) {
        std::cerr << "Error opening file" << std::endl;
        return -1;
    }

    // Store the number of occurrences of each word
    std::vector<int> wordCounts;

    // Read each line of the file
    std::string line;
    while (std::getline(file, line)) {
        // Split the line into words
        std::stringstream ss(line);
        std::string word;
        while (std::getline(ss, word, ' ')) {
            // Check if the word is the one we're looking for
            if (word == "specific_word") {
                // Increment the count for this word
                int count = wordCounts.size();
                if (count == 0) {
                    wordCounts.push_back(1);
                } else {
                    wordCounts[count - 1]++;
                }
            }
        }
    }

    // Print the number of occurrences for each word
    for (int i = 0; i < wordCounts.size(); i++) {
        std::cout << "Word: " << i << " Occurrences: " << wordCounts[i] << std::endl;
    }

    // Close the file
    file.close();

    return 0;
}
